def sum_list(arr):
    total = 0
    for num in arr:
        total += num
    return total

print(sum_list([2, 4, 6, 8]))

def find_largest(arr):
    largest = arr[0]
    for num in arr:
        if num > largest:
            largest = num
    return largest

print(find_largest([3, 9, 2, 8]))

def find_smallest(arr):
    smallest = arr[0]
    for num in arr:
        if num < smallest:
            smallest = num
    return smallest

print(find_smallest([7, 3, 9, 1]))

def count_even(arr):
    count = 0
    for num in arr:
        if num % 2 == 0:
            count += 1
    return count

print(count_even([1, 2, 3, 4, 5, 6]))

def linear_search(arr, target):
    for i in range(len(arr)):
        if arr[i] == target:
            return i
    return -1

print(linear_search([10, 20, 30, 40], 30))

def reverse_list(arr):
    result = []
    for i in range(len(arr) - 1, -1, -1):
        result.append(arr[i])
    return result

print(reverse_list([1, 2, 3, 4]))

def count_occurrences(arr, target):
    count = 0
    for num in arr:
        if num == target:
            count += 1
    return count

print(count_occurrences([2, 3, 2, 5, 2], 2))

def is_palindrome(s):
    left = 0
    right = len(s) - 1

    while left < right:
        if s[left] != s[right]:
            return False
        left += 1
        right -= 1

    return True

print(is_palindrome('madam'))

def count_vowels(s):
    count = 0
    vowels = 'aeiou'

    for ch in s:
        if ch.lower() in vowels:
            count += 1

    return count

print(count_vowels('programming'))

def char_frequency(s):
    freq = {}

    for ch in s:
        if ch in freq:
            freq[ch] += 1
        else:
            freq[ch] = 1

    return freq

print(char_frequency('banana'))

def remove_duplicates(arr):
    result = []

    for num in arr:
        if num not in result:
            result.append(num)

    return result

print(remove_duplicates([1, 2, 2, 3, 1, 4]))

def second_largest(arr):
    largest = None
    second = None

    for num in arr:
        if largest is None or num > largest:
            second = largest
            largest = num
        elif num != largest and (second is None or num > second):
            second = num

    return second

print(second_largest([5, 1, 9, 3]))

def is_sorted(arr):
    for i in range(len(arr) - 1):
        if arr[i] > arr[i + 1]:
            return False
    return True

print(is_sorted([1, 2, 2, 4]))

def bubble_one_pass(arr):
    for i in range(len(arr) - 1):
        if arr[i] > arr[i + 1]:
            arr[i], arr[i + 1] = arr[i + 1], arr[i]
    return arr

print(bubble_one_pass([5, 1, 4, 2]))

def bubble_sort(arr):
    n = len(arr)

    for i in range(n):
        for j in range(0, n - i - 1):
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]

    return arr

print(bubble_sort([4, 1, 3, 2]))

def two_sum(arr, target):
    n = len(arr)

    for i in range(n):
        for j in range(i + 1, n):
            if arr[i] + arr[j] == target:
                return True

    return False

print(two_sum([2, 7, 11, 15], 9))

def left_rotate_one(arr):
    if len(arr) == 0:
        return arr

    first = arr[0]

    for i in range(len(arr) - 1):
        arr[i] = arr[i + 1]

    arr[-1] = first
    return arr

print(left_rotate_one([1, 2, 3, 4]))

def merge_sorted(a, b):
    i = 0
    j = 0
    result = []

    while i < len(a) and j < len(b):
        if a[i] <= b[j]:
            result.append(a[i])
            i += 1
        else:
            result.append(b[j])
            j += 1

    while i < len(a):
        result.append(a[i])
        i += 1

    while j < len(b):
        result.append(b[j])
        j += 1

    return result

print(merge_sorted([1, 3, 5], [2, 4, 6]))

def first_non_repeating(s):
    freq = {}

    for ch in s:
        if ch in freq:
            freq[ch] += 1
        else:
            freq[ch] = 1

    for ch in s:
        if freq[ch] == 1:
            return ch

    return None

print(first_non_repeating('aabbcdd'))

def valid_brackets(s):
    count = 0

    for ch in s:
        if ch == '(':
            count += 1
        elif ch == ')':
            count -= 1

        if count < 0:
            return False

    return count == 0

print(valid_brackets('(()())'))
